using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with default reflection-based metadata
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Got typed metadata for Person: CreateObject is {(personInfo.CreateObject is not null ? "set" : "null")}");

// Serialize using the typed metadata
var json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) Probe without throwing: TryGetTypeInfo returns false if metadata isn't available
//    Use a resolver that only knows about Person, so Widget will not resolve.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new PersonOnlyResolver()
};

if (limited.TryGetTypeInfo(typeof(Person), out var pInfo))
    Console.WriteLine($"Person metadata available: {pInfo!.Type.Name}");
else
    Console.WriteLine("Person metadata NOT available");

if (limited.TryGetTypeInfo(typeof(Widget), out var wInfo))
    Console.WriteLine($"Widget metadata available: {wInfo!.Type.Name}");
else
    Console.WriteLine("Widget metadata NOT available (no exception thrown)");

// --- Types ---
record Person(string Name, int Age);
record Widget(string Id);

// A resolver that only provides metadata for Person
file class PersonOnlyResolver : IJsonTypeInfoResolver
{
    private readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
        => type == typeof(Person) ? _inner.GetTypeInfo(type, options) : null;
}

